INSERT INTO guia.dbo.Arcanos (Numero,Nombre,LetraHebrea,SignificadoEsoterico,Mensaje,ElementoOPlaneta,ImagenUrl) VALUES
	 (0,N'El Loco',N'א (Aleph)',N'Potencial puro e inocencia espiritual.',N'El salto de fe hacia lo desconocido.',N'Aire',N'/img/arcanos/0_loco.png'),
	 (1,N'El Mago',N'ב (Beth)',N'Manifestación y voluntad consciente.',N'Como es arriba, es abajo. Tienes el poder.',N'Mercurio',N'/img/arcanos/1_mago.png'),
	 (2,N'La Sacerdotisa',N'ג (Gimel)',N'Sabiduría oculta y el subconsciente.',N'Escucha el silencio de tu intuición.',N'Luna',N'/img/arcanos/2_sacerdotisa.png'),
	 (3,N'La Emperatriz',N'ד (Daleth)',N'Creatividad, fertilidad y naturaleza.',N'La abundancia florece desde el amor.',N'Venus',N'/img/arcanos/3_emperatriz.png'),
	 (4,N'El Emperador',N'ה (He)',N'Orden, estabilidad y dominio material.',N'Estructura y autoridad con justicia.',N'Aries',N'/img/arcanos/4_emperador.png'),
	 (5,N'El Hierofante',N'ו (Vau)',N'Tradición, enseñanza y valores espirituales.',N'El puente entre lo humano y lo divino.',N'Tauro',N'/img/arcanos/5_hierofante.png'),
	 (6,N'Los Enamorados',N'ז (Zain)',N'Elecciones del corazón y dualidad.',N'La unión de los opuestos en armonía.',N'Géminis',N'/img/arcanos/6_enamorados.png'),
	 (7,N'El Carro',N'ח (Cheth)',N'Control, avance y triunfo sobre obstáculos.',N'Victoria a través de la determinación.',N'Cáncer',N'/img/arcanos/7_carro.png'),
	 (8,N'La Justicia',N'ל (Lamed)',N'Equilibrio kármico y verdad objetiva.',N'Cosechas exactamente lo que has sembrado.',N'Libra',N'/img/arcanos/8_justicia.png'),
	 (9,N'El Ermitaño',N'י (Yod)',N'Introspección, guía y soledad sagrada.',N'La luz que buscas está en tu interior.',N'Virgo',N'/img/arcanos/9_ermitano.png');
INSERT INTO guia.dbo.Arcanos (Numero,Nombre,LetraHebrea,SignificadoEsoterico,Mensaje,ElementoOPlaneta,ImagenUrl) VALUES
	 (10,N'La Rueda de la Fortuna',N'כ (Kaph)',N'Destino, ciclos y giros inesperados.',N'Todo cambia, el ciclo nunca se detiene.',N'Júpiter',N'/img/arcanos/10_rueda_fortuna.png'),
	 (11,N'La Fuerza',N'ט (Teth)',N'Coraje espiritual y compasión.',N'El dominio de la fiera interna con amor.',N'Leo',N'/img/arcanos/11_fuerza.png'),
	 (12,N'El Colgado',N'מ (Mem)',N'Sacrificio, pausa e iluminación.',N'Ver el mundo desde una nueva perspectiva.',N'Agua',N'/img/arcanos/12_colgado.png'),
	 (13,N'La Muerte',N'נ (Nun)',N'Transformación profunda y renacimiento.',N'Lo viejo muere para que nazca lo nuevo.',N'Escorpio',N'/img/arcanos/13_muerte.png'),
	 (14,N'La Templanza',N'ס (Samekh)',N'Moderación, paciencia y propósito.',N'Alquimia emocional y equilibrio.',N'Sagitario',N'/img/arcanos/14_templanza.png'),
	 (15,N'El Diablo',N'ע (Ayin)',N'Sombra, apegos y tentación material.',N'Libérate de las cadenas que tú mismo creaste.',N'Capricornio',N'/img/arcanos/15_diablo.png'),
	 (16,N'La Torre',N'Pe',N'Revelación súbita y liberación forzada.',N'El derrumbe de lo falso para construir verdad.',N'Marte',N'/img/arcanos/16_torre.png'),
	 (17,N'La Estrella',N'Tzaddi',N'Inspiración, fe y sanación.',N'La esperanza es la guía en la oscuridad.',N'Acuario',N'/img/arcanos/17_estrella.png'),
	 (18,N'La Luna',N'Qoph',N'Ilusión, misterio y el inconsciente profundo.',N'Navega tus miedos y confía en tus sueños.',N'Piscis',N'/img/arcanos/18_luna.png'),
	 (19,N'El Sol',N'ר (Resh)',N'Vitalidad, éxito y realización.',N'Éxito, alegría y claridad absoluta.',N'Sol',N'/img/arcanos/19_sol.png');
INSERT INTO guia.dbo.Arcanos (Numero,Nombre,LetraHebrea,SignificadoEsoterico,Mensaje,ElementoOPlaneta,ImagenUrl) VALUES
	 (20,N'El Juicio',N'ש (Shin)',N'Llamado interno, perdón y absolución.',N'El despertar a una nueva vida superior.',N'Fuego',N'/img/arcanos/20_juicio.png'),
	 (21,N'El Mundo',N'ת (Tau)',N'Finalización, integración y unidad.',N'La culminación del viaje, el todo en uno.',N'Saturno',N'/img/arcanos/21_mundo.png');
